import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import { useState, useEffect } from "react";

/**
 * 🚀 MERN STACK ARCHITECTURE - BACKEND & DATABASE INTEGRATION GUIDE
 * =================================================================
 * This project is ready to be connected to a MERN backend. 
 * Below is the blueprint for the second developer:
 * 
 * 1. NODE.JS / EXPRESS BACKEND:
 *    - Create a 'backend' folder in the root.
 *    - Setup an Express server with routes for /api/stocks, /api/auth, and /api/portfolio.
 * 
 * 2. MONGODB DATABASE:
 *    - Use Mongoose to connect to your MongoDB Atlas cluster.
 *    - Collections needed: 'Users' (for profiles), 'Stocks' (for info), 'Transactions' (for orders).
 * 
 * 3. CONNECTION LOGIC:
 *    - In the frontend, replace mock data services (stockService.js) with Axios calls.
 *    - Use JWT Tokens for session persistence in ProtectedRoute.
 * 
 * 📍 CHECK MARKERS: Look for '📍 BACKEND INTEGRATION' comments in:
 *    - /src/services/stockService.js
 *    - /src/pages/Login.jsx
 *    - /src/pages/Dashboard.jsx
 *    - /src/pages/Register.jsx
 */
import Navbar from "./components/Navbar";
import Footer from "./components/Footer";
import Home from "./pages/Home";
import Dashboard from "./pages/Dashboard";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Markets from "./pages/Markets";
import StockDetail from "./pages/StockDetail";
import Watchlist from "./pages/Watchlist";
import Portfolio from "./pages/Portfolio";
import Profile from "./pages/Profile";
import Wallet from "./pages/Wallet";
import Calculator from "./pages/Calculator";
import Resources from "./pages/Resources";

// Protected Route Component - Persists login after refresh
const ProtectedRoute = ({ children }) => {
  // Check localStorage for persisted login session
  const currentUser = localStorage.getItem("currentUser");
  const authToken = localStorage.getItem("authToken");

  // TODO: Backend - Verify token with backend API
  // const isAuthenticated = await verifyToken(authToken);

  // If no user/token in localStorage, redirect to login
  if (!currentUser || !authToken) {
    return <Navigate to="/login" replace />;
  }

  // User is logged in - render the protected content
  return children;
};

// Public Route - Redirects logged-in users to dashboard
const PublicRoute = ({ children }) => {
  const currentUser = localStorage.getItem("currentUser");
  const authToken = localStorage.getItem("authToken");

  // If user is already logged in, redirect to dashboard
  if (currentUser && authToken) {
    return <Navigate to="/dashboard" replace />;
  }

  // User is not logged in - render the public content
  return children;
};

export default function App() {
  const [authState, setAuthState] = useState({
    isAuthenticated: false,
    currentUser: null
  });

  // Listen for auth changes
  useEffect(() => {
    const checkAuth = () => {
      const user = localStorage.getItem("currentUser");
      const token = localStorage.getItem("authToken");
      setAuthState({
        isAuthenticated: !!(user && token),
        currentUser: user ? JSON.parse(user) : null
      });
    };

    // Check on mount
    checkAuth();

    // Listen for storage changes (when user logs in/out in another tab)
    window.addEventListener('storage', checkAuth);

    // Listen for custom auth event
    window.addEventListener('authChange', checkAuth);

    return () => {
      window.removeEventListener('storage', checkAuth);
      window.removeEventListener('authChange', checkAuth);
    };
  }, []);

  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <Navbar authState={authState} setAuthState={setAuthState} />
        <div className="flex-grow">
          <Routes>
            {/* Public Routes */}
            <Route path="/" element={<Home authState={authState} />} />
            <Route
              path="/register"
              element={
                <PublicRoute>
                  <Register />
                </PublicRoute>
              }
            />
            <Route
              path="/login"
              element={
                <PublicRoute>
                  <Login />
                </PublicRoute>
              }
            />

            {/* Protected Routes - Require Login */}
            {/* Backend TODO: Add authentication middleware on all protected routes */}
            <Route path="/dashboard" element={
              <ProtectedRoute>
                <Dashboard />
              </ProtectedRoute>
            } />
            <Route path="/markets" element={<Markets />} />
            <Route path="/stock/:symbol" element={<StockDetail />} />
            <Route path="/calculator" element={<Calculator />} />
            <Route path="/resources" element={<Resources />} />
            <Route path="/watchlist" element={
              <ProtectedRoute>
                <Watchlist />
              </ProtectedRoute>
            } />
            <Route path="/portfolio" element={
              <ProtectedRoute>
                <Portfolio />
              </ProtectedRoute>
            } />
            <Route path="/profile" element={
              <ProtectedRoute>
                <Profile />
              </ProtectedRoute>
            } />
            <Route path="/wallet" element={
              <ProtectedRoute>
                <Wallet />
              </ProtectedRoute>
            } />

            {/* Backend TODO: Add remaining utility routes
              - /orders - Order history
              - /transactions - Transaction history
              - /settings - Account settings
              - /reset-password/:token - Reset password page
            */}
          </Routes>
        </div>
        <Footer />
      </div>
    </Router>
  );
}

